mapper.select:
select r.*, c.course_name, u.real_name as teacher_name from course_resource r left join course_info c on r.course_id = c.id left join sys_user u on r.teacher_id = u.id
and r.schedule_id = #{scheduleId}
and r.teacher_id = #{teacherId}
and r.title like concat('%', #{keyword}, '%')
order by r.id desc

select r.*, c.course_name, u.real_name as teacher_name from course_resource r inner join course_selection cs on r.schedule_id = cs.schedule_id left join course_info c on r.course_id = c.id left join sys_user u on r.teacher_id = u.id where cs.student_id = #{studentId}
and r.title like concat('%', #{keyword}, '%')
order by r.id desc

mapper.update:
update course_resource
schedule_id = #{scheduleId}, course_id = #{courseId}, title = #{title}, resource_type = #{resourceType}, resource_url = #{resourceUrl}, content_desc = #{contentDesc}, status = #{status},
where id = #{id}
